-- ── Step A: Company banao ──────────────────────────────────
VALUES ('Stockwell Solar', 'STOCKWELL')
ON CONFLICT (code) DO NOTHING;

-- ── Step B: Users import ───────────────────────────────────

-- ── Step C: Expenses import ────────────────────────────────


-- ── Step D: Company assign karo ────────────────────────────
UPDATE public.users    SET company_id = (SELECT id FROM public.companies WHERE code = 'STOCKWELL');
UPDATE public.expenses SET company_id = (SELECT id FROM public.companies WHERE code = 'STOCKWELL');

-- ── Step E: Verify ─────────────────────────────────────────
SELECT 'users' AS table_name, COUNT(*) AS total FROM public.users
UNION ALL
SELECT 'expenses', COUNT(*) FROM public.expenses
UNION ALL
SELECT 'companies', COUNT(*) FROM public.companies;
